import 'package:flutter/material.dart';import 'package:go_router/go_router.dart';import '../../core/utils/validators.dart';import '../../core/widgets/app_button.dart';import '../../core/widgets/app_text_field.dart';import '../../core/widgets/empty_view.dart';import '../../core/widgets/loading_view.dart';import '../../services/auth_service.dart';import '../../services/profile_service.dart';
class ProfileScreen extends StatefulWidget{const ProfileScreen({super.key});@override State<ProfileScreen> createState()=>_ProfileScreenState();}
class _ProfileScreenState extends State<ProfileScreen>{final n=TextEditingController(),m=TextEditingController();@override Widget build(BuildContext c){if(!AuthService().isLoggedIn)return Scaffold(appBar:AppBar(title:const Text('Profile')),body:EmptyView(message:'Login to submit predictions and track your score.',action:Wrap(spacing:8,children:[FilledButton(onPressed:()=>c.go('/login?redirect=/profile'),child:const Text('Login')),OutlinedButton(onPressed:()=>c.go('/register?redirect=/profile'),child:const Text('Register'))])));return Scaffold(appBar:AppBar(title:const Text('Profile')),body:FutureBuilder(future:ProfileService().currentProfile(),builder:(c,s){if(s.connectionState==ConnectionState.waiting)return const LoadingView();final p=s.data;n.text=p?.fullName??'';m.text=p?.mobileNumber??'';return ListView(padding:const EdgeInsets.all(16),children:[AppTextField(controller:n,label:'Full Name'),const SizedBox(height:12),AppTextField(controller:m,label:'Mobile Number'),const SizedBox(height:12),Text('Email: ${p?.email ?? AuthService().currentUser?.email ?? ''}'),Text('Private mobile: ${p?.mobileNumber ?? ''}'),Text('Public mobile display: ${Validators.maskMobile(p?.mobileNumber)}'),AppButton(label:'Save Profile',onPressed:()async{await ProfileService().updateProfile(n.text,m.text);if(mounted)setState((){});}),AppButton(label:'Logout',outlined:true,onPressed:()async{await AuthService().logout();if(c.mounted)c.go('/home');setState((){});})]);}));}}
